var b="url",c="往来记账.html",d="generationDate",e=new Date(1781588657934.17),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="017ee1814fac4b50a9d8c36058cb91ff",v="type",w="Axure:Page",x="往来记账",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="f7701cafef3841668f92cec625e557fb",E="label",F="操作时间",G="说明",H="<p><span>1.默认为空，展示全部数据</span></p><p><span>2.选择时包含快捷日期：近一周，近一个月，近三个月</span></p>",I="2",J="87171b69f5e54c0294887d4209c93a66",K="采购应付",L="<p><span>来源[采购结算单]内同一供应商生成的记账单的“结算金额”汇总</span></p><p><span>其他来源，该字段为空</span></p>",M="3",N="921ab514f7914fe598178f8a9e8e47d8",O="外发应付",P="<p><span>来源[外发结算单]内同一共享工厂生成的记账单的“结算金额”汇总</span></p><p><span>其他来源，该字段为空</span></p>",Q="4",R="9ce136dbe3fe4b83a6e7f3338e34b86a",S="调整追加应付",T="<p><span>来源[应收款对单调整]内同一往来单位生成的记账单的“追加应付”汇总</span></p><p><span>其他来源，该字段为空</span></p>",U="5",V="36daa69685c84e98a4b73f53f3332049",W="调整扣除应付",X="<p><span>来源[应收款对单调整]内同一往来单位生成的记账单的“扣除应付”汇总</span></p><p><span>其他来源，该字段为空</span></p>",Y="6",Z="f3a8212d85b541ff88ac78de445f72be",ba="付款金额",bb="<p><span>来源[付款单与冲账]内创建的付款账单内的“付款金额”</span></p><p><span>其他来源，该字段为空</span></p>",bc="7",bd="0dbda9d7124040a3873f7dcee784a162",be="余额冲销",bf="<p><span>来源[付款单与冲账]内创建的付款账单内的“余额冲销”</span></p><p><span>其他来源，该字段为空</span></p>",bg="8",bh="39720a6ef8d141b8bb7965f3f5ca59a1",bi="末期应付",bj="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1.根据该往来单位的上次的“末期应付”及本行记账进行计算（如果该往来单位不存在记录，取[</span><span style=\"color:#333333;\">应付款期初</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">]中的“期初应付”，为空则视为'0.00'）</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; a.根据采购结算单记账时的&quot;结算金额&quot;进行增加</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; b.根据外发结算单记账时的&quot;结算金额&quot;进行增加</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; c.根据付款账单中&quot;本次付款&quot;进行减少</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; d.根据调整记账中&quot;追加应付&quot;进行增加</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; e.根据调整记账中&quot;扣除应付&quot;进行减少</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\"><br></span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">附：记录的是操作时已记账的结算单中共有多少未付金额</span></p>",bk="9",bl="8a5863e2edab49589f4715a3a8c12c47",bm="预付余额",bn="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1.根据该往来单位的上期的“预付余额”及本行记账进行计算（如果该往来单位不存在记录，取[</span><span style=\"color:#333333;\">应付款期初</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">]中的“预付余额”，为空则视为'0.00'）</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; a.根据付款账单中&quot;余额冲销&quot;进行减少</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; b.根据付款账单中&quot;超出应付&quot;进行增加</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp; c.根据调整记账中若扣除部分的金额超过结算单的未付金额，将超出部分增加至预付余额</span></p>",bo="style",bp="baseStyle",bq="627587b6038d43cca051c114ac41ad32",br="pageAlignment",bs="center",bt="fill",bu="fillType",bv="solid",bw="color",bx=0xFFFFFFFF,by="image",bz="imageAlignment",bA="near",bB="imageRepeat",bC="auto",bD="favicon",bE="sketchFactor",bF="0",bG="colorStyle",bH="appliedColor",bI="fontName",bJ="Applied Font",bK="borderWidth",bL="borderVisibility",bM="borderFill",bN=0xFF797979,bO="cornerRadius",bP="cornerVisibility",bQ="outerShadow",bR="on",bS=false,bT="offsetX",bU=5,bV="offsetY",bW="blurRadius",bX="spread",bY="r",bZ=0,ca="g",cb="b",cc="a",cd=0.349019607